const raw = $input.first().json.output || $input.first().json.text || '';
const msg = $('Extract Message').first().json;

try {
  let jsonStr = raw;
  const cb = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (cb) jsonStr = cb[1];
  const s = jsonStr.indexOf('{');
  const e = jsonStr.lastIndexOf('}');
  if (s !== -1 && e !== -1) jsonStr = jsonStr.substring(s, e + 1);

  const parsed = JSON.parse(jsonStr);
  const validIntents = ['FAQ','ORDER_REFUND','COMPLAINT','ESCALATE','GREETING'];

  return [{
    json: {
      customer_phone: msg.customer_phone,
      customer_name: msg.customer_name,
      message: msg.message,
      received_at: msg.received_at,
      intent: validIntents.includes(parsed.intent) ? parsed.intent : 'FAQ',
      language: parsed.language || 'english',
      urgency: parsed.urgency || 'medium',
      reply: parsed.reply || 'Sorry, I could not process your request. Our team will reach out shortly.'
    }
  }];
} catch (e) {
  return [{
    json: {
      customer_phone: msg.customer_phone,
      customer_name: msg.customer_name,
      message: msg.message,
      received_at: msg.received_at,
      intent: 'FAQ',
      language: 'english',
      urgency: 'medium',
      reply: 'Sorry, I could not process your request. Our team will reach out shortly.'
    }
  }];
}

